def seed_hazards(conn):
    cursor = conn.cursor()
    cursor.executemany("""
        INSERT OR REPLACE INTO hazard_item
        (id, source, source_type, category_code, category_name, section_type, inspection_item, hazard_problem, requirement_text, rectification_text, risk_text, image_id)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    """, PROVINCIAL_HAZARDS + DISTRICT_HAZARDS)
    conn.commit()
    print(f"[OK] 导入隐患条目: 595 条省级 + 68 条区级 = 663 条")

def seed_supervision(conn):
    cursor = conn.cursor()
    cursor.executemany("""
        INSERT OR REPLACE INTO supervision_item
        (id, jd_id, project_name, inspection_name, inspection_method, source)
        VALUES (?, ?, ?, ?, ?, ?)
    """, SUPERVISION_ITEMS)
    conn.commit()
    print(f"[OK] 导入监督抽查事项: {len(SUPERVISION_ITEMS)} 条")

    cursor.executemany("""
        INSERT OR REPLACE INTO supervision_condition
        (id, jd_id, condition_order, condition_text, disposal_target, disposal_measure, penalty_basis, source)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    """, SUPERVISION_CONDITIONS)
    conn.commit()
    print(f"[OK] 导入监督问题情形: {len(SUPERVISION_CONDITIONS)} 条")

def seed_links(conn):
    cursor = conn.cursor()
    cursor.executemany("""
        INSERT OR REPLACE INTO hazard_supervision_link
        (hazard_id, jd_id, condition_id, match_type, review_status, notes)
        VALUES (?, ?, ?, ?, ?, ?)
    """, HAZARD_SUPERVISION_LINKS)
    conn.commit()
    print(f"[OK] 导入隐患-监督关联: {len(HAZARD_SUPERVISION_LINKS)} 条")

def seed_images(conn):
    cursor = conn.cursor()
    cursor.executemany("""
        INSERT OR REPLACE INTO image_asset
        (image_id, hazard_id, file_name, oss_object_key, thumb_key, status)
        VALUES (?, ?, ?, ?, ?, "available")
    """, IMAGE_ASSETS)
    conn.commit()
    print(f"[OK] 导入图片资源映射: {len(IMAGE_ASSETS)} 条")

def verify(conn):
    cursor = conn.cursor()
    tables = ["hazard_item", "supervision_item", "supervision_condition", "hazard_supervision_link", "image_asset"]
    print("\n[验证] 各表记录数:")
    for t in tables:
        cursor.execute(f"SELECT COUNT(*) FROM {t}")
        count = cursor.fetchone()[0]
        print(f"  {t}: {count} 条")
    # 按类别统计
    cursor.execute("SELECT category_code, category_name, COUNT(*) FROM hazard_item GROUP BY category_code, category_name ORDER BY category_code")
    print("\n[验证] 各类别隐患数:")
    for row in cursor.fetchall():
        print(f"  {row[0]} {row[1]}: {row[2]} 条")

if __name__ == "__main__":
    os.makedirs(os.path.dirname(DB_PATH), exist_ok=True)
    conn = sqlite3.connect(DB_PATH)
    seed_hazards(conn)
    seed_supervision(conn)
    seed_links(conn)
    seed_images(conn)
    verify(conn)
    conn.close()
    print(f"\n[OK] 数据库已就绪: {DB_PATH}")